/* =========================================================
   ПРЕЛОАДЕР «100 ИСТОРИЙ» — КЛИНИКА ФОМИНА
   Самодостаточный скрипт для Тильды (через jsdelivr CDN)

   Использование в Тильде (блок T123):
     <script src="https://cdn.jsdelivr.net/gh/ПОЛЬЗОВАТЕЛЬ/РЕПОЗИТОРИЙ@main/preloader.js"></script>

   Шрифт 'sexsmth' должен быть уже подключён в настройках Тильды.
   ========================================================= */
(function() {
  'use strict';

  // Облака в base64 (встроены в скрипт)
  var CLOUD_V1 = 'data:image/webp;base64,';
  var CLOUD_V4 = 'data:image/webp;base64,';
  var CLOUD_V5 = 'data:image/webp;base64,';
  var CLOUD_V6 = 'data:image/webp;base64,';

  // HTML-разметка прелоадера
  var HTML = '<div id="fomin-preloader" aria-hidden="true">\n  <div class="fp-sky"></div>\n  <div class="fp-sun"></div>\n\n  <!-- SVG-фильтры рассеивания: создаются динамически в JS по одному на облако -->\n  <svg class="fp-filters" width="0" height="0" aria-hidden="true">\n    <defs id="fp-filter-defs"></defs>\n  </svg>\n\n  <div class="fp-stage" id="fp-stage"></div>\n\n  <!-- канвас для кастомного курсора «Дыхание» (только десктоп) -->\n  <canvas id="fp-cursor" aria-hidden="true"></canvas>\n\n  <!-- счётчик загрузки (правый нижний угол) -->\n  <div class="fp-loader" id="fp-loader" aria-hidden="true">\n    <div class="fp-loader-label">загружаем истории сильных женщин</div>\n    <div class="fp-loader-percent"><span id="fp-loader-num">0</span>%</div>\n  </div>\n</div>';

  // CSS-стили прелоадера
  var CSS = '/* ============ ШРИФТ ============ */\n  /* \'sexsmth\' уже подключён в настройках Тильды → ничего импортировать не надо */\n\n  /* ============ ПАЛИТРА ============ */\n  #fomin-preloader {\n    --fp-sky-top:    #E9F2F9;\n    --fp-sky-mid:    #D4E4F0;\n    --fp-sky-bottom: #BED8EA;\n    --fp-ink:        #1A2833;\n    --fp-ink-soft:   rgba(26, 40, 51, 0.55);\n  }\n\n  /* ============ БАЗОВЫЙ КОНТЕЙНЕР ============ */\n  #fomin-preloader {\n    position: fixed;\n    inset: 0;\n    z-index: 999999;\n    overflow: hidden;\n    cursor: none;   /* системный курсор скрыт, вместо него — canvas "Дыхание" */\n    animation: fp-fade-in 0.5s ease-out both;\n  }\n  /* на мобилке/тач-устройствах возвращаем обычный курсор */\n  @media (hover: none) and (pointer: coarse) {\n    #fomin-preloader { cursor: default; }\n  }\n\n  /* canvas курсора — поверх всей сцены */\n  #fp-cursor {\n    position: absolute;\n    inset: 0;\n    width: 100%;\n    height: 100%;\n    pointer-events: none;\n    z-index: 10;\n  }\n  @media (hover: none) and (pointer: coarse) {\n    #fp-cursor { display: none; }   /* на мобилке не рисуем */\n  }\n\n  /* ============ СЧЁТЧИК ЗАГРУЗКИ ============ */\n  .fp-loader {\n    position: absolute;\n    right: clamp(18px, 3vw, 40px);\n    bottom: clamp(18px, 3vh, 36px);\n    z-index: 20;\n    font-family: \'sexsmth\', Georgia, serif;\n    color: var(--fp-ink);\n    text-align: right;\n    pointer-events: none;\n    opacity: 0;\n    animation: fp-loader-in 0.7s ease-out 0.3s forwards;\n    letter-spacing: 0.01em;\n    line-height: 1.2;\n    /* тонкая белая подсветка для читаемости на светлом небе */\n    text-shadow:\n      0 0 8px rgba(255, 255, 255, 0.6),\n      0 1px 0 rgba(255, 255, 255, 0.3);\n  }\n  @keyframes fp-loader-in {\n    from { opacity: 0; transform: translateY(8px); }\n    to   { opacity: 1; transform: translateY(0); }\n  }\n\n  .fp-loader-label {\n    font-size: clamp(12px, 1.1vw, 15px);\n    color: var(--fp-ink-soft);\n    margin-bottom: 4px;\n    font-weight: 400;\n  }\n\n  .fp-loader-percent {\n    font-size: clamp(28px, 3.2vw, 44px);\n    font-weight: 400;\n    color: var(--fp-ink);\n    line-height: 1;\n    /* табличные цифры — не будет дёргаться ширина при смене цифр */\n    font-variant-numeric: tabular-nums;\n  }\n  @keyframes fp-fade-in { from { opacity: 0; } to { opacity: 1; } }\n  #fomin-preloader.fp-hiding {\n    animation: fp-fade-out 0.9s ease-in forwards;\n    pointer-events: none;\n  }\n  @keyframes fp-fade-out { to { opacity: 0; } }\n\n  .fp-sky {\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(180deg,\n      var(--fp-sky-top)    0%,\n      var(--fp-sky-mid)   45%,\n      var(--fp-sky-bottom) 100%);\n  }\n\n  .fp-sun {\n    position: absolute;\n    top: -30%;\n    left: 50%;\n    transform: translateX(-50%);\n    width: 120%;\n    height: 90%;\n    background: radial-gradient(ellipse at center,\n      rgba(255, 240, 210, 0.55) 0%,\n      rgba(255, 240, 210, 0) 55%);\n    pointer-events: none;\n  }\n\n  .fp-stage { position: absolute; inset: 0; }\n\n  /* ============ ОБЛАКО ============ */\n  .fp-cloud {\n    position: absolute;\n    top: 0; left: 0;\n    transform: translate(-50%, -50%);\n    will-change: transform, opacity, filter;\n    user-select: none;\n    -webkit-user-select: none;\n    pointer-events: auto;\n    animation-name: fp-drift;\n    animation-iteration-count: infinite;\n    animation-timing-function: ease-in-out;\n    animation-direction: alternate;\n  }\n\n  @keyframes fp-drift {\n    0%   { transform: translate(-50%, -50%) translate(0, 0) rotate(var(--rot, 0deg)); }\n    50%  { transform: translate(-50%, -50%) translate(var(--dx, 8px), var(--dy, -8px)) rotate(calc(var(--rot, 0deg) + 0.6deg)); }\n    100% { transform: translate(-50%, -50%) translate(calc(var(--dx, 8px) * -0.6), var(--dy2, 5px)) rotate(calc(var(--rot, 0deg) - 0.6deg)); }\n  }\n\n  /* внутренняя обёртка — задаёт размер и flex-центрирование текста */\n  .fp-cloud-inner {\n    position: relative;\n    display: flex;\n    align-items: center;     /* текст по вертикали в центре */\n    justify-content: center; /* по горизонтали */\n  }\n\n  /* картинка облака — заполняет обёртку как фон */\n  .fp-cloud-img {\n    position: absolute;\n    inset: 0;\n    width: 100%;\n    height: 100%;\n    object-fit: contain;\n    filter: drop-shadow(0 6px 16px rgba(60, 90, 120, 0.15));\n    pointer-events: none;\n  }\n\n  /* текст — flex его центрирует по вертикали, а margin-top сдвигает под оптический центр формы */\n  .fp-cloud-text {\n    position: relative;\n    z-index: 2;\n    text-align: center;\n    font-family: \'sexsmth\', Georgia, serif;\n    font-weight: 400;\n    color: var(--fp-ink);\n    line-height: 1.15;\n    letter-spacing: 0.005em;\n    text-shadow:\n      0 0 8px rgba(255, 255, 255, 0.85),\n      0 0 3px rgba(255, 255, 255, 0.6);\n    pointer-events: none;\n    width: 100%;\n    padding: 0 6%;\n    box-sizing: border-box;\n    /* запрещаем разрыв слов посередине */\n    word-break: keep-all;\n    overflow-wrap: normal;\n    hyphens: none;\n  }\n  .fp-cloud-text > span {\n    display: block;\n    /* на мобилке даём переноситься целыми словами, если не влезает в одну строку */\n    white-space: normal;\n  }\n  /* на десктопе — строго одна строка на span, как задумано */\n  @media (hover: hover) and (pointer: fine) {\n    .fp-cloud-text > span {\n      white-space: nowrap;\n    }\n  }\n\n  /* ============ SMOKE DISPERSE (мягкое дымовое рассеивание) ============ */\n  /* Эффект: облако плавно раздувается, поднимается вверх, размывается и гаснет —\n     как дым от сигареты. SVG-displacement подмешивается очень мягко, чтобы форма\n     теряла геометричность и выглядела органично, а не "улетала блюром". */\n\n  .fp-cloud.fp-dispersing {\n    pointer-events: none;\n    animation: none !important;\n  }\n\n  .fp-cloud.fp-dispersing .fp-cloud-inner {\n    /* filter url() и transform задаются инлайном из JS */\n    will-change: filter, opacity, transform;\n  }\n\n  /* текст тает синхронно с облаком, мягче и дольше */\n  .fp-cloud.fp-dispersing .fp-cloud-text {\n    animation: fp-text-fade 1.1s ease-out forwards;\n  }\n  @keyframes fp-text-fade {\n    0%   { opacity: 1; filter: blur(0px); }\n    40%  { opacity: 0.6; filter: blur(1.5px); }\n    100% { opacity: 0; filter: blur(5px); }\n  }\n\n  @media (prefers-reduced-motion: reduce) {\n    .fp-cloud { animation: none !important; }\n    #fomin-preloader { animation: none !important; }\n  }';

  // Инжектим стили
  var styleEl = document.createElement('style');
  styleEl.textContent = CSS;
  document.head.appendChild(styleEl);

  // Инжектим HTML в начало body
  function inject() {
    var wrapper = document.createElement('div');
    wrapper.innerHTML = HTML;
    document.body.insertBefore(wrapper.firstChild, document.body.firstChild);
    runPreloader();
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', inject);
  } else {
    inject();
  }

  function runPreloader() {

  var preloader = document.getElementById('fomin-preloader');
  var stage = document.getElementById('fp-stage');
  if (!preloader || !stage) return;

  // ============ 5 ВАРИАНТОВ ОБЛАКОВ ============
  // offsetY — сдвиг текста вниз от геометрического центра (доля от высоты облака),
  // замерено по визуальному центру "белой массы" каждой формы
  var CLOUD_VARIANTS = [
    { src: CLOUD_V1, ratio: 600/289, offsetY: 0.075 },   // v1 ассиметричное
    { src: CLOUD_V4, ratio: 600/281, offsetY: 0.048 },   // v4 составное с двумя горбами
    { src: CLOUD_V5, ratio: 600/180, offsetY: 0.074 },   // v5 плоское вытянутое
    { src: CLOUD_V6, ratio: 600/369, offsetY: 0.096 },   // v6 высокое с башенкой
    { src: CLOUD_V1, ratio: 600/289, offsetY: 0.075, flip: true }
  ];

  var PHRASES = [
    'Просто отпусти',
    'Может ты на самом деле\nне хочешь ребёнка?',
    'Видимо бог не дал',
    'Надо было раньше думать,\nтеперь-то чего',
    'Вам бы расслабиться\nи всё получится',
    'ЭКО — это против природы',
    'Надо принять это\nи смириться',
    'Не каждой дано\nстать матерью',
    'Значит, не судьба'
  ];

  // какое облако для какой фразы — подобрано вручную, чтобы длинные фразы
  // ложились на широкие облака, короткие — на компактные
  var PHRASE_TO_VARIANT = [
    0, // "Просто отпусти" → v1 обычное
    1, // длинная → v4 широкое составное
    4, // "Видимо бог не дал" → v1 зеркально
    1, // длинная → v4
    4, // длинная → v1 зеркально
    2, // "ЭКО против природы" → v5 плоское
    0, // "Надо принять это" → v1
    2, // "Не каждой дано" → v5 плоское
    3  // "Значит не судьба" → v6 высокое (короткая фраза, но высокое облако = текст внизу)
  ];

  var isTouch = matchMedia('(hover: none) and (pointer: coarse)').matches;

  // ============ СЛОТЫ ============
  var SLOTS = [
    { x: 0.14, y: 0.20, s: 0.95, o: 0.96, fontPx: 21 },
    { x: 0.50, y: 0.15, s: 1.15, o: 1.00, fontPx: 22 },
    { x: 0.86, y: 0.24, s: 0.80, o: 0.90, fontPx: 19 },
    { x: 0.16, y: 0.54, s: 1.00, o: 0.95, fontPx: 21 },
    { x: 0.50, y: 0.50, s: 1.20, o: 1.00, fontPx: 23 },
    { x: 0.82, y: 0.56, s: 0.95, o: 0.92, fontPx: 21 },
    { x: 0.22, y: 0.82, s: 0.82, o: 0.88, fontPx: 19 },
    { x: 0.54, y: 0.80, s: 1.00, o: 0.94, fontPx: 21 },
    { x: 0.85, y: 0.75, s: 0.78, o: 0.82, fontPx: 17 }
  ];

  if (isTouch) {
    SLOTS = [
      { x: 0.28, y: 0.09, s: 0.62, o: 0.95, fontPx: 14 },
      { x: 0.70, y: 0.17, s: 0.62, o: 0.95, fontPx: 14 },
      { x: 0.22, y: 0.26, s: 0.60, o: 0.90, fontPx: 13 },
      { x: 0.72, y: 0.36, s: 0.68, o: 1.00, fontPx: 14 },
      { x: 0.28, y: 0.46, s: 0.70, o: 0.95, fontPx: 14 },
      { x: 0.72, y: 0.55, s: 0.62, o: 0.92, fontPx: 14 },
      { x: 0.26, y: 0.64, s: 0.62, o: 0.90, fontPx: 13 },
      { x: 0.70, y: 0.72, s: 0.60, o: 0.85, fontPx: 13 },
      { x: 0.30, y: 0.78, s: 0.55, o: 0.80, fontPx: 13 }
    ];
  }

  function clamp(v, min, max){ return Math.max(min, Math.min(max, v)); }

  var rootW = window.innerWidth;
  var rootH = window.innerHeight;

  // масштаб сцены для нешироких десктопов
  var stageScale = 1;
  if (!isTouch) {
    if (rootW >= 1280) stageScale = 1;
    else if (rootW >= 960) stageScale = 0.80 + (rootW - 960) / 320 * 0.20;
    else stageScale = Math.max(0.62, 0.68 + (rootW - 768) / 192 * 0.12);
  }

  var BASE_CLOUD_W = 320;  // ширина облака в пикселях при scale=1

  // ============ СОЗДАНИЕ ОБЛАКОВ ============
  var clouds = [];

  for (var i = 0; i < PHRASES.length; i++) {
    var slot = SLOTS[i];
    var variant = CLOUD_VARIANTS[PHRASE_TO_VARIANT[i]];

    var cloudEl = document.createElement('div');
    cloudEl.className = 'fp-cloud';
    cloudEl.style.opacity = slot.o;

    // idle-дрейф — свой для каждого
    var rot  = (Math.random() * 4 - 2).toFixed(2);
    var dx   = (5 + Math.random() * 8).toFixed(1);
    var dy   = (-3 - Math.random() * 8).toFixed(1);
    var dy2  = (2 + Math.random() * 6).toFixed(1);
    var dur  = (6 + Math.random() * 4).toFixed(2);
    var del  = (-Math.random() * 6).toFixed(2);
    cloudEl.style.setProperty('--rot', rot + 'deg');
    cloudEl.style.setProperty('--dx',  dx  + 'px');
    cloudEl.style.setProperty('--dy',  dy  + 'px');
    cloudEl.style.setProperty('--dy2', dy2 + 'px');
    cloudEl.style.animationDuration = dur + 's';
    cloudEl.style.animationDelay = del + 's';

    // размеры облака с учётом scale и пропорций ТОГО облака
    var effScale = slot.s * stageScale;
    var widthPx  = BASE_CLOUD_W * effScale;
    var heightPx = widthPx / variant.ratio;

    // на мобилке ограничиваем ширину
    if (isTouch && widthPx > rootW * 0.88) {
      widthPx = rootW * 0.88;
      heightPx = widthPx / variant.ratio;
    }

    // clamp позиции
    var margin = 10;
    var xPx = clamp(slot.x * rootW, widthPx/2 + margin, rootW - widthPx/2 - margin);
    var yPx = clamp(slot.y * rootH, heightPx/2 + margin, rootH - heightPx/2 - margin - 40);
    cloudEl.style.left = xPx + 'px';
    cloudEl.style.top  = yPx + 'px';

    // внутренняя обёртка — размер + flex-центрирование текста
    var inner = document.createElement('div');
    inner.className = 'fp-cloud-inner';
    inner.style.width = widthPx + 'px';
    inner.style.height = heightPx + 'px';
    if (variant.flip) inner.style.transform = 'scaleX(-1)';

    // картинка — на заднем плане
    var img = document.createElement('img');
    img.className = 'fp-cloud-img';
    img.src = variant.src;
    img.alt = '';
    img.draggable = false;
    inner.appendChild(img);

    // текст — flex центрирует, margin-top сдвигает на оптический центр формы
    var textEl = document.createElement('div');
    textEl.className = 'fp-cloud-text';
    // сдвиг вниз на процент от фактической высоты облака
    var offsetPx = Math.round(heightPx * variant.offsetY);
    textEl.style.marginTop = offsetPx + 'px';
    var fontPx = Math.max(11, Math.round(slot.fontPx * (isTouch ? 1 : stageScale)));
    textEl.style.fontSize = fontPx + 'px';
    // если облако отзеркалено — текст компенсируем scaleX(-1)
    if (variant.flip) {
      textEl.style.transform = 'scaleX(-1)';
    }

    // строки — каждая в span, чтобы nowrap работал построчно
    var lines = PHRASES[i].split('\n');
    for (var li = 0; li < lines.length; li++) {
      var span = document.createElement('span');
      span.textContent = lines[li];
      textEl.appendChild(span);
    }

    inner.appendChild(textEl);
    cloudEl.appendChild(inner);
    stage.appendChild(cloudEl);

    clouds.push({
      el: cloudEl,
      index: i,
      dispersed: false,
      cx: xPx,
      cy: yPx,
      radiusX: widthPx * 0.42,
      radiusY: heightPx * 0.42
    });
  }

  // ============ SVG-ФИЛЬТР ДЛЯ КАЖДОГО ОБЛАКА ============
  // мягкий displacement + gaussian blur. Отдельный filter на облако с уникальным seed,
  // чтобы визуально рассеивания не повторялись
  var filterDefs = document.getElementById('fp-filter-defs');
  var SVG_NS = 'http://www.w3.org/2000/svg';

  function createDisperseFilter(id, seed) {
    var filter = document.createElementNS(SVG_NS, 'filter');
    filter.setAttribute('id', id);
    // расширяем область фильтра, чтобы blur и displacement не обрезались
    filter.setAttribute('x', '-50%');
    filter.setAttribute('y', '-50%');
    filter.setAttribute('width', '200%');
    filter.setAttribute('height', '200%');
    filter.setAttribute('color-interpolation-filters', 'sRGB');

    // лёгкая турбулентность — только для органичности формы, не для "распада"
    var turb = document.createElementNS(SVG_NS, 'feTurbulence');
    turb.setAttribute('type', 'fractalNoise');
    turb.setAttribute('baseFrequency', '0.008');   // крупный мягкий шум
    turb.setAttribute('numOctaves', '2');
    turb.setAttribute('seed', String(seed));
    turb.setAttribute('result', 'noise');

    var disp = document.createElementNS(SVG_NS, 'feDisplacementMap');
    disp.setAttribute('in', 'SourceGraphic');
    disp.setAttribute('in2', 'noise');
    disp.setAttribute('scale', '0');
    disp.setAttribute('xChannelSelector', 'R');
    disp.setAttribute('yChannelSelector', 'G');
    disp.setAttribute('result', 'displaced');

    // gaussian blur после displacement — главное, что делает эффект "дымовым"
    var blur = document.createElementNS(SVG_NS, 'feGaussianBlur');
    blur.setAttribute('in', 'displaced');
    blur.setAttribute('stdDeviation', '0');

    filter.appendChild(turb);
    filter.appendChild(disp);
    filter.appendChild(blur);
    filterDefs.appendChild(filter);

    return { filter: filter, turb: turb, disp: disp, blur: blur };
  }

  // ============ РАССЕИВАНИЕ ОДНОГО ОБЛАКА (дымом) ============
  var DISPERSE_MS = 1600;   // плавно, не спеша

  function disperse(cloud) {
    if (cloud.dispersed) return;
    cloud.dispersed = true;

    var filterId = 'fp-disp-' + cloud.index;
    var fx = createDisperseFilter(filterId, Math.floor(Math.random() * 1000));

    var inner = cloud.el.querySelector('.fp-cloud-inner');
    inner.style.filter = 'url(#' + filterId + ')';
    cloud.el.classList.add('fp-dispersing');

    // сохраняем базовый transform (flip если есть)
    var baseTransform = inner.style.transform || '';

    var startTime = performance.now();
    // лёгкое искажение формы — только чтобы края не были идеально гладкими
    var peakDispScale = 12 + Math.random() * 10;      // 12..22 (было 180..260 — жёстко)
    // gaussian blur — главный "дымовой" компонент
    var peakBlur      = 10 + Math.random() * 6;       // 10..16 px
    // scale-up — облако раздувается, как облачко пара
    var peakGrow      = 1.25 + Math.random() * 0.15;  // 1.25..1.40
    // подъём вверх — тёплый воздух поднимает дым
    var peakRise      = 25 + Math.random() * 20;      // 25..45 px
    // лёгкий боковой дрейф, чтобы каждое облако таяло индивидуально
    var peakDriftX    = (Math.random() - 0.5) * 30;   // -15..+15

    function animateFrame(now) {
      var t = (now - startTime) / DISPERSE_MS;
      if (t >= 1) {
        if (cloud.el.parentNode) cloud.el.parentNode.removeChild(cloud.el);
        if (fx.filter.parentNode) fx.filter.parentNode.removeChild(fx.filter);
        return;
      }

      // ease-out cubic — быстрое начало, плавное замедление к концу
      var e = 1 - Math.pow(1 - t, 3);
      // для blur используем более мягкую кривую, чтобы размытие нарастало постепенно
      var eBlur = Math.pow(t, 0.8);

      // 1) Displacement — очень мягкий, облако "дышит" без жёстких разводов
      fx.disp.setAttribute('scale', (peakDispScale * e).toFixed(1));

      // 2) Gaussian blur — главный компонент "дыма"
      fx.blur.setAttribute('stdDeviation', (peakBlur * eBlur).toFixed(2));

      // 3) Scale + translateY + translateX через inline transform на обёртке
      var grow  = 1 + (peakGrow - 1) * e;
      var rise  = peakRise * e;
      var drift = peakDriftX * e;
      // формируем transform: сначала flip (если был), потом дымовое движение
      var smokeTransform = 'translate(' + drift.toFixed(1) + 'px, ' + (-rise).toFixed(1) + 'px) scale(' + grow.toFixed(3) + ')';
      inner.style.transform = (baseTransform ? baseTransform + ' ' : '') + smokeTransform;

      // 4) Opacity — медленное угасание, но к концу гарантированно 0
      //    используем ease-in чтобы первая половина анимации была хорошо видна
      var fadeT = Math.pow(t, 1.6);
      cloud.el.style.opacity = Math.max(0, 1 - fadeT).toFixed(3);

      requestAnimationFrame(animateFrame);
    }
    requestAnimationFrame(animateFrame);
  }

  // ============ ОСНОВНОЙ ТАЙМЕР: 3 СЕКУНДЫ ============
  var TOTAL_MS     = 3000;
  var FADE_OUT_MS  = 600;

 var finished = false;
  function hidePreloader() {
    if (finished) return;
    finished = true;
    preloader.classList.add('fp-hiding');
    setTimeout(function(){
      if (preloader.parentNode) preloader.parentNode.removeChild(preloader);
      
      // ВОТ ЭТА СТРОЧКА: она возвращает скролл и показывает сайт
      document.body.classList.remove('loading-process');
      
    }, FADE_OUT_MS + 50);
  }

  setTimeout(hidePreloader, TOTAL_MS - FADE_OUT_MS);

  // ============ СЧЁТЧИК ПРОЦЕНТОВ (0→100% за TOTAL_MS) ============
  // плавно растёт от 0% до 100% за время жизни прелоадера с лёгким ease-out,
  // чтобы в конце не "тормозил" на последних процентах
  (function animatePercent() {
    var numEl = document.getElementById('fp-loader-num');
    if (!numEl) return;
    var startAt = performance.now();
    var duration = TOTAL_MS - FADE_OUT_MS;   // синхронно с жизнью прелоадера
    function step(now) {
      var t = Math.min(1, (now - startAt) / duration);
      // мягкий ease-out cubic — начинается бодро, замедляется к 100%
      var eased = 1 - Math.pow(1 - t, 2.5);
      var pct = Math.floor(eased * 100);
      numEl.textContent = pct;
      if (t < 1 && !finished) requestAnimationFrame(step);
      else numEl.textContent = 100;
    }
    requestAnimationFrame(step);
  })();

  // ============ DESKTOP: ХУВЕР + КУРСОР «ДЫХАНИЕ» ============
  if (!isTouch) {
    var lastMouse = { x: -9999, y: -9999 };
    window.addEventListener('mousemove', function(e){
      lastMouse.x = e.clientX;
      lastMouse.y = e.clientY;
    }, { passive: true });

    // ---- настройка canvas-курсора ----
    var cursorCanvas = document.getElementById('fp-cursor');
    var cursorCtx = cursorCanvas ? cursorCanvas.getContext('2d') : null;
    var dpr = window.devicePixelRatio || 1;

    function resizeCursor() {
      if (!cursorCanvas) return;
      cursorCanvas.width  = window.innerWidth  * dpr;
      cursorCanvas.height = window.innerHeight * dpr;
      cursorCtx.setTransform(1, 0, 0, 1, 0, 0);  // сбрасываем
      cursorCtx.scale(dpr, dpr);
    }
    resizeCursor();
    window.addEventListener('resize', resizeCursor);

    // сглаженная позиция курсора (с инерцией = "дыхание")
    var cursor = { x: lastMouse.x, y: lastMouse.y };
    // хвост из точек {x, y, life}
    var cursorTrail = [];
    var cursorPhase = 0;  // фаза пульсации "вдох-выдох"

    function drawCursor() {
      if (!cursorCtx) return;
      // очищаем канвас
      cursorCtx.clearRect(0, 0, window.innerWidth, window.innerHeight);

      // пока мышь не двигалась — не рисуем ничего
      if (lastMouse.x < -9998) return;

      // инициализация после первого mousemove
      if (cursor.x < -9998) {
        cursor.x = lastMouse.x;
        cursor.y = lastMouse.y;
      }

      // сглаживание: меньше коэффициент = сильнее инерция
      cursor.x += (lastMouse.x - cursor.x) * 0.18;
      cursor.y += (lastMouse.y - cursor.y) * 0.18;

      // добавляем точку в хвост
      cursorTrail.push({ x: cursor.x, y: cursor.y, life: 1 });
      if (cursorTrail.length > 28) cursorTrail.shift();

      // ---- тающий хвост-дымок ----
      for (var i = 0; i < cursorTrail.length; i++) {
        var p = cursorTrail[i];
        var size = 11 * p.life;
        if (size < 1) continue;
        var g = cursorCtx.createRadialGradient(p.x, p.y, 0, p.x, p.y, size);
        g.addColorStop(0, 'rgba(255, 255, 255, ' + (0.22 * p.life) + ')');
        g.addColorStop(1, 'rgba(255, 255, 255, 0)');
        cursorCtx.fillStyle = g;
        cursorCtx.beginPath();
        cursorCtx.arc(p.x, p.y, size, 0, Math.PI * 2);
        cursorCtx.fill();
        p.life -= 0.045;
      }
      cursorTrail = cursorTrail.filter(function(p){ return p.life > 0; });

      // ---- основной курсор: облачко с пульсацией "дыхания" ----
      cursorPhase += 0.035;
      var breathPulse = 1 + Math.sin(cursorPhase) * 0.08;
      var r = 13 * breathPulse;

      // внешний ореол
      var outer = cursorCtx.createRadialGradient(cursor.x, cursor.y, 0, cursor.x, cursor.y, r * 2.3);
      outer.addColorStop(0,   'rgba(255, 255, 255, 0.5)');
      outer.addColorStop(0.5, 'rgba(255, 255, 255, 0.18)');
      outer.addColorStop(1,   'rgba(255, 255, 255, 0)');
      cursorCtx.fillStyle = outer;
      cursorCtx.beginPath();
      cursorCtx.arc(cursor.x, cursor.y, r * 2.3, 0, Math.PI * 2);
      cursorCtx.fill();

      // плотный центр
      var core = cursorCtx.createRadialGradient(cursor.x, cursor.y, 0, cursor.x, cursor.y, r);
      core.addColorStop(0,   'rgba(255, 255, 255, 0.9)');
      core.addColorStop(0.6, 'rgba(255, 255, 255, 0.5)');
      core.addColorStop(1,   'rgba(255, 255, 255, 0)');
      cursorCtx.fillStyle = core;
      cursorCtx.beginPath();
      cursorCtx.arc(cursor.x, cursor.y, r, 0, Math.PI * 2);
      cursorCtx.fill();
    }

    // ---- единый rAF-цикл: проверка попадания + рендер курсора ----
    function tick() {
      if (finished) return;

      // 1) проверка попадания курсора в эллипс каждого облака
      for (var k = 0; k < clouds.length; k++) {
        var c = clouds[k];
        if (c.dispersed) continue;
        var dx = lastMouse.x - c.cx;
        var dy = lastMouse.y - c.cy;
        var inside = (dx*dx) / (c.radiusX * c.radiusX) + (dy*dy) / (c.radiusY * c.radiusY) < 1;
        if (inside) disperse(c);
      }

      // 2) рендер кастомного курсора
      drawCursor();

      requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }

  // ============ MOBILE: ТАП ============
  if (isTouch) {
    stage.addEventListener('click', function(e){
      var target = e.target.closest('.fp-cloud');
      if (!target) return;
      for (var m = 0; m < clouds.length; m++) {
        if (clouds[m].el === target) {
          disperse(clouds[m]);
          break;
        }
      }
    });
  }

  // Escape — мгновенное закрытие (для отладки/a11y)
  window.addEventListener('keydown', function(e){
    if (e.key === 'Escape') hidePreloader();
  });
  }
})();
